import React, { useState } from 'react';
import PendingSubmissions from './pages/PendingSubmissions';
import RhymesList from './pages/RhymesList';
import GiftsList from './pages/GiftsList';
import UsersList from './pages/UsersList';

function App() {
  const [currentPage, setCurrentPage] = useState('pending');

  return (
    <div style={{ padding: '24px', fontFamily: 'Arial, sans-serif' }}>
      <h1>GINJ Admin Dashboard</h1>
      <nav style={{ marginBottom: 24 }}>
        <button onClick={() => setCurrentPage('pending')} style={{ marginRight: 8 }}>
          Pending Submissions
        </button>
        <button onClick={() => setCurrentPage('rhymes')} style={{ marginRight: 8 }}>
          Rhymes List
        </button>
        <button onClick={() => setCurrentPage('gifts')} style={{ marginRight: 8 }}>
          Gift List
        </button>
        <button onClick={() => setCurrentPage('users')}>
          Users
        </button>
      </nav>
      {currentPage === 'pending' && <PendingSubmissions />}
      {currentPage === 'rhymes' && <RhymesList />}
      {currentPage === 'gifts' && <GiftsList />}
      {currentPage === 'users' && <UsersList />}
    </div>
  );
}

export default App;
